{
  "name": "Gestão de Manutenção de Básculas",
  "description": "Aplicação para gestão de contratos de manutenção, histórico de equipamentos e visitas técnicas para básculas e balanças industriais.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum EquipmentType {
  PCM = 'PCM',
  PVS = 'PVS',
  PVM = 'PVM',
  Other = 'Outro'
}

export enum VisitType {
  RECONSTRUCTION = 'Reconstrução',
  ASSIST_LIGHT = 'Assistência Ligeira',
  ASSIST_TRUCK = 'Assistência Camião'
}

export interface Visit {
  id: string;
  equipmentId: string;
  date: string;
  type: VisitType;
  technician: string;
  notes: string;
  files: string[]; // Placeholder for file names/urls
  viewerChanged?: boolean;
  oldViewerSerial?: string;
  newViewerSerial?: string;
}

export interface Contract {
  id: string;
  equipmentId: string;
  startDate: string;
  endDate: string;
  invoiceNumber: string;
  paymentDate?: string;
  isPaid: boolean;
  totalLightVisits: number;
  usedLightVisits: number;
  totalTruckVisits: number;
  usedTruckVisits: number;
}

export interface Equipment {
  id: string;
  clientId: string;
  location: string;
  productName: string; // e.g., "Báscula Ponte"
  weightCapacity: string; // e.g., "60 Ton"
  installDate: string;
  type: EquipmentType;
  equipmentSerial: string;
  viewerModel: string;
  viewerSerial: string;
  visits: Visit[];
  contract?: Contract;
}

export interface Client {
  id: string;
  name: string;
  address: string;
  contactPerson: string;
  email: string;
  phone: string;
  equipments: Equipment[];
}

export type PageView = 'DASHBOARD' | 'CLIENTS' | 'CALENDAR';

import { GoogleGenAI } from "@google/genai";
import { Client, Equipment } from "../types";

const apiKey = process.env.API_KEY || '';

// Initialize client safely (it might fail if key is missing, handled in call)
const ai = new GoogleGenAI({ apiKey });

export const generateAssistantResponse = async (
  prompt: string,
  contextData: { clients: Client[], currentView: string }
): Promise<string> => {
  if (!apiKey) {
    return "API Key não configurada. Por favor configure a variável de ambiente API_KEY.";
  }

  try {
    // Prepare a lightweight context summary
    const dataSummary = contextData.clients.map(c => ({
      name: c.name,
      contact: c.contactPerson,
      equipments: c.equipments.map(e => ({
        local: e.location,
        model: e.productName,
        serial: e.equipmentSerial,
        paid: e.contract?.isPaid ? 'Sim' : 'Não',
        visitsLeftLight: (e.contract?.totalLightVisits || 0) - (e.contract?.usedLightVisits || 0),
        visitsLeftTruck: (e.contract?.totalTruckVisits || 0) - (e.contract?.usedTruckVisits || 0),
      }))
    }));

    const systemInstruction = `
      És um assistente inteligente para uma aplicação de gestão de manutenção de básculas.
      O teu objetivo é ajudar o técnico ou gestor a encontrar informações, resumir contratos ou sugerir ações.
      Responde sempre em Português de Portugal.
      Sê conciso e profissional.

      Dados Atuais do Sistema (Resumo JSON):
      ${JSON.stringify(dataSummary)}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
        thinkingConfig: { thinkingBudget: 0 } // Fast response for UI chat
      }
    });

    return response.text || "Não foi possível gerar uma resposta.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Desculpe, ocorreu um erro ao contactar a IA.";
  }
};

import React, { useState } from 'react';
import { VisitType, Equipment } from '../types';
import { X, Upload, Calendar, User, FileText, Activity } from 'lucide-react';

interface VisitModalProps {
  equipment: Equipment;
  onClose: () => void;
  onSave: (visitData: any) => void;
}

const VisitModal: React.FC<VisitModalProps> = ({ equipment, onClose, onSave }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<VisitType>(VisitType.ASSIST_LIGHT);
  const [technician, setTechnician] = useState('');
  const [notes, setNotes] = useState('');
  const [newViewerSerial, setNewViewerSerial] = useState('');
  const [files, setFiles] = useState<File[]>([]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      date,
      type,
      technician,
      notes,
      files: files.map(f => f.name), // Mocking file upload by just taking names
      viewerChanged: type === VisitType.RECONSTRUCTION,
      newViewerSerial: type === VisitType.RECONSTRUCTION ? newViewerSerial : undefined
    });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      setFiles(Array.from(e.target.files));
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="bg-blue-600 p-4 flex justify-between items-center text-white">
          <h3 className="font-semibold text-lg flex items-center gap-2">
            <Activity className="w-5 h-5" />
            Registar Visita / Intervenção
          </h3>
          <button onClick={onClose} className="hover:bg-blue-700 p-1 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
                <input
                  type="date"
                  required
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full pl-9 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tipo de Visita</label>
              <select
                value={type}
                onChange={(e) => setType(e.target.value as VisitType)}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {Object.values(VisitType).map((t) => (
                  <option key={t} value={t}>{t}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Técnico Responsável</label>
            <div className="relative">
              <User className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
              <input
                type="text"
                required
                value={technician}
                onChange={(e) => setTechnician(e.target.value)}
                placeholder="Nome do técnico"
                className="w-full pl-9 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>
          </div>

          {type === VisitType.RECONSTRUCTION && (
            <div className="bg-amber-50 border border-amber-200 rounded-lg p-4">
              <h4 className="text-sm font-semibold text-amber-800 mb-2">Dados da Reconstrução</h4>
              <p className="text-xs text-amber-700 mb-3">
                A visita de reconstrução implica calibração e substituição do visor. Indique o novo serial.
              </p>
              <div>
                <label className="block text-xs font-bold text-amber-900 uppercase tracking-wide mb-1">
                  Novo Nº Série Visor
                </label>
                <input
                  type="text"
                  required
                  value={newViewerSerial}
                  onChange={(e) => setNewViewerSerial(e.target.value)}
                  placeholder="Ex: DD-9921-NEW"
                  className="w-full px-3 py-2 border border-amber-300 rounded bg-white focus:ring-2 focus:ring-amber-500 outline-none"
                />
              </div>
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Relatório / Observações</label>
            <textarea
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none"
              placeholder="Descreva o trabalho realizado..."
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Anexos (Certificados, Fotos)</label>
            <div className="flex items-center justify-center w-full">
              <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-slate-300 border-dashed rounded-lg cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors">
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <Upload className="w-6 h-6 text-slate-400 mb-2" />
                  <p className="text-sm text-slate-500">
                    <span className="font-semibold">Clique para carregar</span>
                  </p>
                  <p className="text-xs text-slate-400">PDF, JPG, PNG</p>
                </div>
                <input type="file" className="hidden" multiple onChange={handleFileChange} />
              </label>
            </div>
            {files.length > 0 && (
              <ul className="mt-2 space-y-1">
                {files.map((f, i) => (
                  <li key={i} className="text-xs flex items-center text-slate-600">
                    <FileText className="w-3 h-3 mr-1" /> {f.name}
                  </li>
                ))}
              </ul>
            )}
          </div>

          <div className="pt-2 flex justify-end gap-3">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-lg hover:bg-slate-50"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 shadow-md shadow-blue-200"
            >
              Registar Visita
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default VisitModal;

import React, { useState } from 'react';
import { Client } from '../types';
import { Search, MapPin, Phone, Building2, ChevronRight } from 'lucide-react';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
}

const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.contactPerson.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 h-full flex flex-col">
      <div className="p-4 border-b border-slate-100">
        <h2 className="text-lg font-bold text-slate-800 mb-3">Carteira de Clientes</h2>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
          <input
            type="text"
            placeholder="Pesquisar cliente ou contacto..."
            className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-2 space-y-2">
        {filteredClients.length === 0 ? (
          <div className="text-center py-10 text-slate-400">
            <Building2 className="w-10 h-10 mx-auto mb-2 opacity-50" />
            <p>Nenhum cliente encontrado.</p>
          </div>
        ) : (
          filteredClients.map(client => (
            <button
              key={client.id}
              onClick={() => onSelectClient(client)}
              className="w-full text-left p-4 rounded-lg hover:bg-slate-50 border border-transparent hover:border-slate-200 transition-all group group-hover:shadow-sm"
            >
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="font-semibold text-slate-800 group-hover:text-blue-600 transition-colors">
                    {client.name}
                  </h3>
                  <div className="mt-1 space-y-1">
                    <p className="text-xs text-slate-500 flex items-center">
                      <MapPin className="w-3 h-3 mr-1.5" />
                      {client.address}
                    </p>
                    <p className="text-xs text-slate-500 flex items-center">
                      <UserIcon className="w-3 h-3 mr-1.5" />
                      {client.contactPerson}
                    </p>
                    <p className="text-xs text-slate-500 flex items-center">
                      <Phone className="w-3 h-3 mr-1.5" />
                      {client.phone}
                    </p>
                  </div>
                </div>
                <ChevronRight className="w-5 h-5 text-slate-300 group-hover:text-blue-400" />
              </div>
              <div className="mt-3 flex items-center gap-2">
                <span className="px-2 py-0.5 bg-blue-50 text-blue-700 text-[10px] font-medium rounded-full border border-blue-100">
                  {client.equipments.length} Equipamentos
                </span>
                {client.equipments.some(e => !e.contract?.isPaid) && (
                   <span className="px-2 py-0.5 bg-red-50 text-red-700 text-[10px] font-medium rounded-full border border-red-100">
                     Pagamento Pendente
                   </span>
                )}
              </div>
            </button>
          ))
        )}
      </div>
    </div>
  );
};

// Helper icon
const UserIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><path d="M19 21v-2a4 4 0 0 0-4-4H9a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
);

export default ClientList;

import React from 'react';
import { Client } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { TrendingUp, AlertTriangle, CheckCircle, Wrench } from 'lucide-react';

interface DashboardProps {
  clients: Client[];
}

const Dashboard: React.FC<DashboardProps> = ({ clients }) => {
  // Calculated stats
  const totalEquipments = clients.reduce((acc, c) => acc + c.equipments.length, 0);
  const paidContracts = clients.reduce((acc, c) => acc + c.equipments.filter(e => e.contract?.isPaid).length, 0);
  const unpaidContracts = totalEquipments - paidContracts;

  const totalVisits = clients.reduce((acc, c) => 
    acc + c.equipments.reduce((vAcc, e) => vAcc + e.visits.length, 0), 0
  );

  const contractData = [
    { name: 'Pagos', value: paidContracts, color: '#22c55e' },
    { name: 'Pendentes', value: unpaidContracts, color: '#ef4444' },
  ];

  // Mock monthly data derived from install dates (just for visualization)
  const activityData = [
    { name: 'Jan', reconstrucoes: 2, assistencias: 5 },
    { name: 'Fev', reconstrucoes: 1, assistencias: 3 },
    { name: 'Mar', reconstrucoes: 3, assistencias: 6 },
    { name: 'Abr', reconstrucoes: 0, assistencias: 4 },
    { name: 'Mai', reconstrucoes: 4, assistencias: 8 },
  ];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <StatCard 
          title="Total Equipamentos" 
          value={totalEquipments} 
          icon={<TrendingUp className="text-blue-600" />} 
          bg="bg-blue-50"
        />
        <StatCard 
          title="Contratos Pagos" 
          value={paidContracts} 
          icon={<CheckCircle className="text-green-600" />} 
          bg="bg-green-50"
        />
        <StatCard 
          title="Pagamento Pendente" 
          value={unpaidContracts} 
          icon={<AlertTriangle className="text-red-600" />} 
          bg="bg-red-50"
        />
         <StatCard 
          title="Total Intervenções" 
          value={totalVisits} 
          icon={<Wrench className="text-amber-600" />} 
          bg="bg-amber-50"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Estado dos Contratos</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={contractData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {contractData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center gap-4 mt-2">
            {contractData.map(d => (
              <div key={d.name} className="flex items-center text-sm text-slate-600">
                <div className="w-3 h-3 rounded-full mr-2" style={{ backgroundColor: d.color }} />
                {d.name}: {d.value}
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Atividade Recente</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={activityData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis axisLine={false} tickLine={false} />
                <Tooltip cursor={{ fill: '#f1f5f9' }} />
                <Bar dataKey="reconstrucoes" name="Reconstruções" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                <Bar dataKey="assistencias" name="Assistências" fill="#94a3b8" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, bg }: { title: string, value: number, icon: React.ReactNode, bg: string }) => (
  <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center justify-between">
    <div>
      <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">{title}</p>
      <p className="text-2xl font-bold text-slate-800 mt-1">{value}</p>
    </div>
    <div className={`p-3 rounded-lg ${bg}`}>
      {icon}
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useRef, useEffect } from 'react';
import { generateAssistantResponse } from '../services/geminiService';
import { Client } from '../types';
import { Bot, Send, Loader2, Sparkles, X } from 'lucide-react';

interface GeminiAssistantProps {
  clients: Client[];
  isOpen: boolean;
  onToggle: () => void;
}

const GeminiAssistant: React.FC<GeminiAssistantProps> = ({ clients, isOpen, onToggle }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'ai'; text: string }[]>([
    { role: 'ai', text: 'Olá! Sou o assistente de manutenção. Como posso ajudar com os contratos ou equipamentos hoje?' }
  ]);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setLoading(true);

    const response = await generateAssistantResponse(userMsg, { clients, currentView: 'Sidebar' });

    setMessages(prev => [...prev, { role: 'ai', text: response }]);
    setLoading(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={onToggle}
        className="fixed bottom-6 right-6 p-4 bg-gradient-to-r from-indigo-600 to-violet-600 text-white rounded-full shadow-lg shadow-indigo-300 hover:scale-105 transition-transform z-40 flex items-center gap-2"
      >
        <Sparkles className="w-6 h-6" />
        <span className="font-semibold hidden md:inline">IA Assistant</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-96 h-[600px] bg-white rounded-2xl shadow-2xl border border-indigo-100 flex flex-col overflow-hidden z-40 animate-in slide-in-from-bottom-10 duration-300">
      {/* Header */}
      <div className="bg-gradient-to-r from-indigo-600 to-violet-600 p-4 flex justify-between items-center text-white">
        <div className="flex items-center gap-2">
          <Bot className="w-6 h-6" />
          <div>
            <h3 className="font-bold text-sm">Assistente Inteligente</h3>
            <p className="text-[10px] opacity-80">Powered by Gemini</p>
          </div>
        </div>
        <button onClick={onToggle} className="hover:bg-white/20 p-1 rounded-full">
          <X className="w-5 h-5" />
        </button>
      </div>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50" ref={scrollRef}>
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-br-none' 
                  : 'bg-white border border-slate-200 text-slate-700 rounded-bl-none shadow-sm'
              }`}
            >
              {msg.text.split('\n').map((line, i) => <p key={i} className="mb-1 last:mb-0">{line}</p>)}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-bl-none shadow-sm">
              <Loader2 className="w-5 h-5 text-indigo-500 animate-spin" />
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-3 bg-white border-t border-slate-100">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Pergunte sobre contratos, visitas..."
            className="w-full pl-4 pr-10 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
          />
          <button 
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="absolute right-2 top-2 p-1.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 transition-colors"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default GeminiAssistant;

import React, { useState } from 'react';
import { Client, PageView, Equipment, VisitType, Visit } from './types';
import { MOCK_CLIENTS } from './constants';
import ClientList from './components/ClientList';
import Dashboard from './components/Dashboard';
import VisitModal from './components/VisitModal';
import GeminiAssistant from './components/GeminiAssistant';
import { 
  LayoutDashboard, 
  Users, 
  CalendarCheck, 
  Settings, 
  Plus, 
  Scale, 
  CreditCard,
  History,
  AlertCircle,
  MapPin,
  Calendar,
  FileText
} from 'lucide-react';

const App = () => {
  const [view, setView] = useState<PageView>('DASHBOARD');
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [selectedEquipment, setSelectedEquipment] = useState<Equipment | null>(null);
  const [isVisitModalOpen, setIsVisitModalOpen] = useState(false);
  const [isAssistantOpen, setIsAssistantOpen] = useState(false);

  // --- Handlers ---

  const handleAddVisit = (visitData: any) => {
    if (!selectedEquipment || !selectedClient) return;

    const newVisit: Visit = {
      id: Math.random().toString(36).substr(2, 9),
      equipmentId: selectedEquipment.id,
      ...visitData
    };

    // Deep clone to update state immutably
    const updatedClients = clients.map(c => {
      if (c.id === selectedClient.id) {
        return {
          ...c,
          equipments: c.equipments.map(e => {
            if (e.id === selectedEquipment.id) {
              const updatedEquip = {
                ...e,
                visits: [newVisit, ...e.visits], // Add visit to history
                // Update contract usage
                contract: e.contract ? {
                  ...e.contract,
                  usedLightVisits: visitData.type === VisitType.ASSIST_LIGHT 
                    ? e.contract.usedLightVisits + 1 
                    : e.contract.usedLightVisits,
                  usedTruckVisits: visitData.type === VisitType.ASSIST_TRUCK
                    ? e.contract.usedTruckVisits + 1
                    : e.contract.usedTruckVisits
                } : undefined,
                // Update viewer if needed
                viewerSerial: visitData.viewerChanged ? visitData.newViewerSerial : e.viewerSerial
              };
              // Update local selection state
              setSelectedEquipment(updatedEquip);
              return updatedEquip;
            }
            return e;
          })
        };
      }
      return c;
    });

    setClients(updatedClients);

    // Refresh selected client reference
    const updatedSelectedClient = updatedClients.find(c => c.id === selectedClient.id);
    if(updatedSelectedClient) setSelectedClient(updatedSelectedClient);

    setIsVisitModalOpen(false);
  };

  const checkContractStatus = (equip: Equipment) => {
    if (!equip.contract) return 'Sem Contrato';
    if (!equip.contract.isPaid) return 'Pagamento Pendente';

    const today = new Date();
    const end = new Date(equip.contract.endDate);
    if (end < today) return 'Expirado';

    return 'Ativo';
  };

  // --- Render Sections ---

  const renderClientDetail = () => {
    if (!selectedClient) return null;
    return (
      <div className="flex h-full gap-6 animate-in fade-in duration-300">
        {/* Left: Client Info & Equipment List */}
        <div className="w-1/3 space-y-4 flex flex-col h-full">
           <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
              <div className="flex justify-between items-start mb-2">
                <h2 className="text-xl font-bold text-slate-800">{selectedClient.name}</h2>
                <span className="text-xs font-mono bg-slate-100 text-slate-500 px-2 py-1 rounded">ID: {selectedClient.id}</span>
              </div>
              <div className="space-y-2 text-sm text-slate-600">
                <p className="flex items-center"><MapPin className="w-4 h-4 mr-2 text-slate-400"/> {selectedClient.address}</p>
                <p className="flex items-center"><Users className="w-4 h-4 mr-2 text-slate-400"/> {selectedClient.contactPerson}</p>
              </div>
           </div>

           <div className="flex-1 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
             <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
               <h3 className="font-semibold text-slate-700">Equipamentos</h3>
               <button className="p-1 hover:bg-slate-200 rounded text-slate-500"><Plus className="w-4 h-4" /></button>
             </div>
             <div className="overflow-y-auto p-2">
               {selectedClient.equipments.map(eq => (
                 <div 
                   key={eq.id}
                   onClick={() => setSelectedEquipment(eq)}
                   className={`p-3 rounded-lg cursor-pointer transition-all border mb-2 ${selectedEquipment?.id === eq.id ? 'bg-blue-50 border-blue-200 shadow-sm' : 'bg-white border-transparent hover:border-slate-200 hover:bg-slate-50'}`}
                 >
                    <div className="flex justify-between items-start">
                      <p className="font-semibold text-sm text-slate-800">{eq.productName}</p>
                      <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-medium ${
                        checkContractStatus(eq) === 'Ativo' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {checkContractStatus(eq)}
                      </span>
                    </div>
                    <p className="text-xs text-slate-500 mt-1 truncate">{eq.location}</p>
                    <p className="text-xs font-mono text-slate-400 mt-1">{eq.equipmentSerial}</p>
                 </div>
               ))}
             </div>
           </div>
        </div>

        {/* Right: Equipment Detail */}
        <div className="w-2/3 h-full flex flex-col">
          {selectedEquipment ? (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 h-full flex flex-col">
              {/* Header */}
              <div className="p-6 border-b border-slate-100 flex justify-between items-start bg-slate-50 rounded-t-xl">
                 <div>
                   <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                     <Scale className="w-5 h-5 text-blue-600" />
                     {selectedEquipment.productName}
                   </h2>
                   <p className="text-sm text-slate-500 mt-1">{selectedEquipment.location}</p>
                 </div>
                 <div className="text-right">
                   <p className="text-sm font-semibold text-slate-700">Capacidade: {selectedEquipment.weightCapacity}</p>
                   <p className="text-xs text-slate-500">Instalado: {selectedEquipment.installDate}</p>
                 </div>
              </div>

              {/* Content Grid */}
              <div className="p-6 grid grid-cols-2 gap-6 overflow-y-auto">
                 {/* Technical Specs */}
                 <div className="space-y-4">
                    <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wide border-b border-slate-100 pb-2">Detalhes Técnicos</h4>
                    <div className="grid grid-cols-2 gap-4 text-sm">
                       <div>
                         <p className="text-slate-500 text-xs">Tipo</p>
                         <p className="font-medium text-slate-700">{selectedEquipment.type}</p>
                       </div>
                       <div>
                         <p className="text-slate-500 text-xs">Nº Série Equip.</p>
                         <p className="font-medium text-slate-700 font-mono">{selectedEquipment.equipmentSerial}</p>
                       </div>
                       <div>
                         <p className="text-slate-500 text-xs">Modelo Visor</p>
                         <p className="font-medium text-slate-700">{selectedEquipment.viewerModel}</p>
                       </div>
                       <div>
                         <p className="text-slate-500 text-xs">Nº Série Visor</p>
                         <p className="font-medium text-slate-700 font-mono bg-yellow-50 px-2 py-0.5 rounded w-fit">
                           {selectedEquipment.viewerSerial}
                         </p>
                       </div>
                    </div>
                 </div>

                 {/* Contract Status */}
                 <div className="space-y-4">
                    <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wide border-b border-slate-100 pb-2 flex justify-between">
                      <span>Estado Contrato</span>
                      {selectedEquipment.contract?.isPaid ? 
                        <span className="text-green-600 flex items-center gap-1 text-xs normal-case"><CheckIcon className="w-3 h-3"/> Pago</span> : 
                        <span className="text-red-600 flex items-center gap-1 text-xs normal-case"><AlertCircle className="w-3 h-3"/> Pendente</span>
                      }
                    </h4>
                    {selectedEquipment.contract ? (
                      <div className="space-y-3">
                         <div className="flex justify-between text-sm">
                           <span className="text-slate-500">Período:</span>
                           <span className="font-medium">{selectedEquipment.contract.startDate} a {selectedEquipment.contract.endDate}</span>
                         </div>
                         <div className="flex justify-between text-sm">
                           <span className="text-slate-500">Fatura:</span>
                           <span className="font-medium">{selectedEquipment.contract.invoiceNumber}</span>
                         </div>

                         <div className="bg-slate-50 p-3 rounded-lg space-y-2">
                           <p className="text-xs font-semibold text-slate-700">Saldo de Visitas:</p>
                           <div className="flex items-center justify-between text-xs">
                             <span>Ligeiros</span>
                             <div className="flex items-center gap-2">
                               <div className="w-24 h-2 bg-slate-200 rounded-full overflow-hidden">
                                 <div 
                                   className="h-full bg-blue-500" 
                                   style={{ width: `${(selectedEquipment.contract.usedLightVisits / selectedEquipment.contract.totalLightVisits) * 100}%` }}
                                 />
                               </div>
                               <span className="font-mono">{selectedEquipment.contract.usedLightVisits}/{selectedEquipment.contract.totalLightVisits}</span>
                             </div>
                           </div>
                           <div className="flex items-center justify-between text-xs">
                             <span>Camião</span>
                             <div className="flex items-center gap-2">
                               <div className="w-24 h-2 bg-slate-200 rounded-full overflow-hidden">
                                 <div 
                                   className="h-full bg-purple-500" 
                                   style={{ width: `${(selectedEquipment.contract.usedTruckVisits / selectedEquipment.contract.totalTruckVisits) * 100}%` }}
                                 />
                               </div>
                               <span className="font-mono">{selectedEquipment.contract.usedTruckVisits}/{selectedEquipment.contract.totalTruckVisits}</span>
                             </div>
                           </div>
                         </div>

                         <div className="pt-2">
                           {selectedEquipment.contract.isPaid ? (
                             <button 
                               onClick={() => setIsVisitModalOpen(true)}
                               className="w-full py-2 bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium rounded-lg transition-colors flex items-center justify-center gap-2"
                             >
                               <Calendar className="w-4 h-4" /> Agendar / Registar Visita
                             </button>
                           ) : (
                              <div className="w-full py-2 bg-slate-100 text-slate-500 text-sm font-medium rounded-lg text-center cursor-not-allowed flex items-center justify-center gap-2">
                                <CreditCard className="w-4 h-4" /> Aguarda Pagamento
                              </div>
                           )}
                         </div>

                      </div>
                    ) : (
                      <p className="text-sm text-slate-500 italic">Sem contrato ativo.</p>
                    )}
                 </div>
              </div>

              {/* History Section */}
              <div className="flex-1 bg-slate-50 p-6 overflow-hidden flex flex-col border-t border-slate-200">
                <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wide mb-4 flex items-center gap-2">
                  <History className="w-4 h-4" /> Histórico de Intervenções
                </h4>
                <div className="overflow-y-auto space-y-3 pr-2">
                  {selectedEquipment.visits.length === 0 ? (
                    <p className="text-sm text-slate-400 text-center py-4">Sem registo de visitas.</p>
                  ) : (
                    selectedEquipment.visits.map(visit => (
                      <div key={visit.id} className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm">
                        <div className="flex justify-between items-start mb-2">
                           <div>
                             <p className="font-semibold text-sm text-slate-800">{visit.type}</p>
                             <p className="text-xs text-slate-500">{visit.date} • Técnico: {visit.technician}</p>
                           </div>
                           {visit.files.length > 0 && <FileText className="w-4 h-4 text-slate-400" />}
                        </div>
                        <p className="text-sm text-slate-600 bg-slate-50 p-2 rounded">{visit.notes}</p>
                        {visit.viewerChanged && (
                          <p className="text-xs text-amber-700 mt-2 font-medium">
                            ⚠️ Visor trocado: {visit.oldViewerSerial} ➔ {visit.newViewerSerial}
                          </p>
                        )}
                      </div>
                    ))
                  )}
                </div>
              </div>

            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl bg-slate-50">
              <Scale className="w-12 h-12 mb-3 opacity-50" />
              <p>Selecione um equipamento para ver detalhes</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  // --- Main Layout ---
  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">

      {/* Sidebar Navigation */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col shadow-xl z-20">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold tracking-tight text-blue-400">ScaleManager</h1>
          <p className="text-xs text-slate-400 mt-1">Gestão de Manutenção</p>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <NavItem 
            icon={<LayoutDashboard />} 
            label="Dashboard" 
            active={view === 'DASHBOARD'} 
            onClick={() => setView('DASHBOARD')} 
          />
          <NavItem 
            icon={<Users />} 
            label="Clientes & Equipamentos" 
            active={view === 'CLIENTS'} 
            onClick={() => setView('CLIENTS')} 
          />
          <NavItem 
            icon={<CalendarCheck />} 
            label="Agenda" 
            active={view === 'CALENDAR'} 
            onClick={() => setView('CALENDAR')} 
          />
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 rounded-lg bg-slate-800/50 text-sm">
            <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center font-bold">JD</div>
            <div>
              <p className="font-medium">João Dias</p>
              <p className="text-xs text-slate-400">Técnico Sénior</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 shadow-sm z-10">
          <h2 className="text-lg font-semibold text-slate-700">
            {view === 'DASHBOARD' && 'Visão Geral'}
            {view === 'CLIENTS' && 'Gestão de Clientes'}
            {view === 'CALENDAR' && 'Agenda de Visitas'}
          </h2>
          <div className="flex items-center gap-4">
            <button className="p-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors">
              <Settings className="w-5 h-5" />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-hidden p-6 relative">
          {view === 'DASHBOARD' && <Dashboard clients={clients} />}

          {view === 'CLIENTS' && (
            <div className="flex h-full gap-6">
              {!selectedClient ? (
                <div className="w-full">
                  <ClientList 
                    clients={clients} 
                    onSelectClient={(c) => {
                      setSelectedClient(c);
                      setSelectedEquipment(null);
                    }} 
                  />
                </div>
              ) : (
                <div className="w-full h-full flex flex-col">
                  <button 
                    onClick={() => setSelectedClient(null)}
                    className="mb-4 text-sm text-slate-500 hover:text-blue-600 flex items-center gap-1 w-fit"
                  >
                    ← Voltar à lista
                  </button>
                  <div className="flex-1 overflow-hidden">
                    {renderClientDetail()}
                  </div>
                </div>
              )}
            </div>
          )}

          {view === 'CALENDAR' && (
             <div className="h-full flex items-center justify-center text-slate-400 bg-white rounded-xl border border-slate-200 border-dashed">
               <div className="text-center">
                 <Calendar className="w-16 h-16 mx-auto mb-4 opacity-20" />
                 <p className="text-lg font-medium">Módulo de Agenda</p>
                 <p className="text-sm">Funcionalidade em desenvolvimento.</p>
               </div>
             </div>
          )}
        </div>
      </main>

      {/* Modals & Overlays */}
      {isVisitModalOpen && selectedEquipment && (
        <VisitModal 
          equipment={selectedEquipment} 
          onClose={() => setIsVisitModalOpen(false)} 
          onSave={handleAddVisit} 
        />
      )}

      <GeminiAssistant 
        clients={clients} 
        isOpen={isAssistantOpen} 
        onToggle={() => setIsAssistantOpen(!isAssistantOpen)} 
      />

    </div>
  );
};

// --- Helper Components ---

const NavItem = ({ icon, label, active, onClick }: { icon: React.ReactNode, label: string, active: boolean, onClick: () => void }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all duration-200 ${
      active 
        ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' 
        : 'text-slate-400 hover:bg-slate-800 hover:text-white'
    }`}
  >
    {React.cloneElement(icon as React.ReactElement, { className: 'w-5 h-5' })}
    {label}
  </button>
);

const CheckIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><polyline points="20 6 9 17 4 12"/></svg>
);

export default App;

import React, { useState } from 'react';
import { X, CreditCard, Calendar } from 'lucide-react';
import { Contract } from '../types';

interface PaymentModalProps {
  contract: Contract;
  onClose: () => void;
  onSave: (paymentData: { date: string, invoice: string }) => void;
}

const PaymentModal: React.FC<PaymentModalProps> = ({ contract, onClose, onSave }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [invoice, setInvoice] = useState(contract.invoiceNumber || '');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({ date, invoice });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-sm animate-in fade-in zoom-in duration-200">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-green-50 rounded-t-xl">
          <h3 className="font-semibold text-green-800 flex items-center gap-2">
            <CreditCard className="w-5 h-5" />
            Registar Pagamento
          </h3>
          <button onClick={onClose} className="hover:bg-green-100 text-green-700 p-1 rounded-full">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Data do Pagamento</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
              <input
                type="date"
                required
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full pl-9 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Número da Fatura</label>
            <input
              type="text"
              required
              value={invoice}
              onChange={(e) => setInvoice(e.target.value)}
              placeholder="Ex: FT 2024/000"
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
            />
          </div>

          <div className="pt-2">
            <button
              type="submit"
              className="w-full py-2 text-sm font-medium text-white bg-green-600 rounded-lg hover:bg-green-700 shadow-md shadow-green-200"
            >
              Confirmar Pagamento
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default PaymentModal;

import React, { useState } from 'react';
import { Client } from '../types';
import { Search, MapPin, Phone, Building2, ChevronRight, UserPlus } from 'lucide-react';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onAddClient?: () => void;
}

const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onAddClient }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.contactPerson.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 h-full flex flex-col">
      <div className="p-4 border-b border-slate-100 space-y-3">
        <div className="flex justify-between items-center">
            <h2 className="text-lg font-bold text-slate-800">Carteira de Clientes</h2>
            {onAddClient && (
                <button 
                  onClick={onAddClient}
                  className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                  title="Adicionar Novo Cliente"
                >
                    <UserPlus className="w-4 h-4" />
                </button>
            )}
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
          <input
            type="text"
            placeholder="Pesquisar cliente ou contacto..."
            className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-2 space-y-2">
        {filteredClients.length === 0 ? (
          <div className="text-center py-10 text-slate-400">
            <Building2 className="w-10 h-10 mx-auto mb-2 opacity-50" />
            <p>Nenhum cliente encontrado.</p>
          </div>
        ) : (
          filteredClients.map(client => (
            <button
              key={client.id}
              onClick={() => onSelectClient(client)}
              className="w-full text-left p-4 rounded-lg hover:bg-slate-50 border border-transparent hover:border-slate-200 transition-all group group-hover:shadow-sm"
            >
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="font-semibold text-slate-800 group-hover:text-blue-600 transition-colors">
                    {client.name}
                  </h3>
                  <div className="mt-1 space-y-1">
                    <p className="text-xs text-slate-500 flex items-center">
                      <MapPin className="w-3 h-3 mr-1.5" />
                      {client.address}
                    </p>
                    <p className="text-xs text-slate-500 flex items-center">
                      <UserIcon className="w-3 h-3 mr-1.5" />
                      {client.contactPerson}
                    </p>
                    <p className="text-xs text-slate-500 flex items-center">
                      <Phone className="w-3 h-3 mr-1.5" />
                      {client.phone}
                    </p>
                  </div>
                </div>
                <ChevronRight className="w-5 h-5 text-slate-300 group-hover:text-blue-400" />
              </div>
              <div className="mt-3 flex items-center gap-2">
                <span className="px-2 py-0.5 bg-blue-50 text-blue-700 text-[10px] font-medium rounded-full border border-blue-100">
                  {client.equipments.length} Equipamentos
                </span>
                {client.equipments.some(e => !e.contract?.isPaid) && (
                   <span className="px-2 py-0.5 bg-red-50 text-red-700 text-[10px] font-medium rounded-full border border-red-100">
                     Pagamento Pendente
                   </span>
                )}
              </div>
            </button>
          ))
        )}
      </div>
    </div>
  );
};

