import React, { useState, useRef, useEffect } from 'react';
import { generateAssistantResponse } from '../services/geminiService';
import { Client } from '../types';
import { Bot, Send, Loader2, Sparkles, X } from 'lucide-react';

interface GeminiAssistantProps {
  clients: Client[];
  isOpen: boolean;
  onToggle: () => void;
}

const GeminiAssistant: React.FC<GeminiAssistantProps> = ({ clients, isOpen, onToggle }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'ai'; text: string }[]>([
    { role: 'ai', text: 'Olá! Sou o assistente de manutenção. Como posso ajudar com os contratos ou equipamentos hoje?' }
  ]);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setLoading(true);

    const response = await generateAssistantResponse(userMsg, { clients, currentView: 'Sidebar' });

    setMessages(prev => [...prev, { role: 'ai', text: response }]);
    setLoading(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={onToggle}
        className="fixed bottom-6 right-6 p-4 bg-gradient-to-r from-indigo-600 to-violet-600 text-white rounded-full shadow-lg shadow-indigo-300 hover:scale-105 transition-transform z-40 flex items-center gap-2"
      >
        <Sparkles className="w-6 h-6" />
        <span className="font-semibold hidden md:inline">IA Assistant</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-96 h-[600px] bg-white rounded-2xl shadow-2xl border border-indigo-100 flex flex-col overflow-hidden z-40 animate-in slide-in-from-bottom-10 duration-300">
      {/* Header */}
      <div className="bg-gradient-to-r from-indigo-600 to-violet-600 p-4 flex justify-between items-center text-white">
        <div className="flex items-center gap-2">
          <Bot className="w-6 h-6" />
          <div>
            <h3 className="font-bold text-sm">Assistente Inteligente</h3>
            <p className="text-[10px] opacity-80">Powered by Gemini</p>
          </div>
        </div>
        <button onClick={onToggle} className="hover:bg-white/20 p-1 rounded-full">
          <X className="w-5 h-5" />
        </button>
      </div>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50" ref={scrollRef}>
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-br-none' 
                  : 'bg-white border border-slate-200 text-slate-700 rounded-bl-none shadow-sm'
              }`}
            >
              {msg.text.split('\n').map((line, i) => <p key={i} className="mb-1 last:mb-0">{line}</p>)}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-bl-none shadow-sm">
              <Loader2 className="w-5 h-5 text-indigo-500 animate-spin" />
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-3 bg-white border-t border-slate-100">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Pergunte sobre contratos, visitas..."
            className="w-full pl-4 pr-10 py-3 bg-white text-slate-900 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
          />
          <button 
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="absolute right-2 top-2 p-1.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 transition-colors"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default GeminiAssistant;

import React, { useState } from 'react';
import { Client, PageView, Equipment, VisitType, Visit } from './types';
import { MOCK_CLIENTS } from './constants';
import ClientList from './components/ClientList';
import Dashboard from './components/Dashboard';
import VisitModal from './components/VisitModal';
import AddClientModal from './components/AddClientModal';
import AddEquipmentModal from './components/AddEquipmentModal';
import PaymentModal from './components/PaymentModal';
import GeminiAssistant from './components/GeminiAssistant';
import { 
  LayoutDashboard, 
  Users, 
  CalendarCheck, 
  Settings, 
  Plus, 
  Scale, 
  CreditCard,
  History,
  AlertCircle,
  MapPin,
  Calendar,
  FileText,
  Edit2
} from 'lucide-react';

const App = () => {
  const [view, setView] = useState<PageView>('DASHBOARD');
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [selectedEquipment, setSelectedEquipment] = useState<Equipment | null>(null);

  // Modal States
  const [isVisitModalOpen, setIsVisitModalOpen] = useState(false);
  const [isAssistantOpen, setIsAssistantOpen] = useState(false);
  const [isAddClientModalOpen, setIsAddClientModalOpen] = useState(false);
  const [isAddEquipmentModalOpen, setIsAddEquipmentModalOpen] = useState(false);
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);

  // Edit States
  const [editingClient, setEditingClient] = useState<Client | undefined>(undefined);
  const [editingEquipment, setEditingEquipment] = useState<Equipment | undefined>(undefined);
  const [editingVisit, setEditingVisit] = useState<Visit | undefined>(undefined);

  // --- Handlers ---

  const handleSaveClient = (clientData: any) => {
    if (editingClient) {
      // Update existing
      const updatedClients = clients.map(c => 
        c.id === editingClient.id ? { ...c, ...clientData } : c
      );
      setClients(updatedClients);
      if (selectedClient && selectedClient.id === editingClient.id) {
        setSelectedClient({ ...selectedClient, ...clientData });
      }
      setEditingClient(undefined);
    } else {
      // Create new
      const newClient: Client = {
        id: Math.random().toString(36).substr(2, 9),
        ...clientData,
        equipments: []
      };
      setClients([...clients, newClient]);
    }
    setIsAddClientModalOpen(false);
  };

  const handleSaveEquipment = (data: any) => {
    if (!selectedClient) return;

    if (editingEquipment) {
      // Update existing
       const updatedClients = clients.map(c => {
        if (c.id === selectedClient.id) {
          return {
            ...c,
            equipments: c.equipments.map(e => {
              if (e.id === editingEquipment.id) {
                const updatedEquip = {
                  ...e,
                  location: data.location,
                  productName: data.productName,
                  weightCapacity: data.weightCapacity,
                  installDate: data.installDate,
                  type: data.type,
                  equipmentSerial: data.equipmentSerial,
                  viewerModel: data.viewerModel,
                  viewerSerial: data.viewerSerial,
                  contract: e.contract ? {
                    ...e.contract,
                    startDate: data.contractStartDate,
                    endDate: data.contractEndDate,
                    invoiceNumber: data.contractInvoice,
                    totalLightVisits: data.totalLightVisits,
                    totalTruckVisits: data.totalTruckVisits,
                    isPaid: data.isPaid,
                    renewed: data.renewed,
                    renewalDate: data.renewalDate
                  } : e.contract
                };
                if(selectedEquipment?.id === updatedEquip.id) setSelectedEquipment(updatedEquip);
                return updatedEquip;
              }
              return e;
            })
          };
        }
        return c;
      });
      setClients(updatedClients);
      const updatedClient = updatedClients.find(c => c.id === selectedClient.id);
      if(updatedClient) setSelectedClient(updatedClient);
      setEditingEquipment(undefined);
    } else {
      // Create new
      const newEquipment: Equipment = {
        id: Math.random().toString(36).substr(2, 9),
        clientId: selectedClient.id,
        location: data.location,
        productName: data.productName,
        weightCapacity: data.weightCapacity,
        installDate: data.installDate,
        type: data.type,
        equipmentSerial: data.equipmentSerial,
        viewerModel: data.viewerModel,
        viewerSerial: data.viewerSerial,
        visits: [],
        contract: {
          id: Math.random().toString(36).substr(2, 9),
          equipmentId: '', // Set below
          startDate: data.contractStartDate,
          endDate: data.contractEndDate,
          invoiceNumber: data.contractInvoice,
          isPaid: data.isPaid,
          totalLightVisits: data.totalLightVisits,
          usedLightVisits: 0,
          totalTruckVisits: data.totalTruckVisits,
          usedTruckVisits: 0,
          renewed: data.renewed,
          renewalDate: data.renewalDate
        }
      };
      if(newEquipment.contract) newEquipment.contract.equipmentId = newEquipment.id;

      const updatedClients = clients.map(c => {
        if (c.id === selectedClient.id) {
          return {
            ...c,
            equipments: [...c.equipments, newEquipment]
          };
        }
        return c;
      });

      setClients(updatedClients);
      const updatedClient = updatedClients.find(c => c.id === selectedClient.id);
      if(updatedClient) setSelectedClient(updatedClient);
    }

    setIsAddEquipmentModalOpen(false);
  };

  const handleRegisterPayment = (paymentData: { date: string, invoice: string }) => {
    if (!selectedEquipment || !selectedClient || !selectedEquipment.contract) return;

    const updatedClients = clients.map(c => {
      if (c.id === selectedClient.id) {
        return {
          ...c,
          equipments: c.equipments.map(e => {
            if (e.id === selectedEquipment.id && e.contract) {
               const updatedEquip = {
                 ...e,
                 contract: {
                   ...e.contract,
                   isPaid: true,
                   paymentDate: paymentData.date,
                   invoiceNumber: paymentData.invoice
                 }
               };
               setSelectedEquipment(updatedEquip); // Update local selected state immediately
               return updatedEquip;
            }
            return e;
          })
        };
      }
      return c;
    });

    setClients(updatedClients);
    const updatedClient = updatedClients.find(c => c.id === selectedClient.id);
    if(updatedClient) setSelectedClient(updatedClient);

    setIsPaymentModalOpen(false);
  };

  const handleSaveVisit = (visitData: any) => {
    if (!selectedEquipment || !selectedClient) return;

    const updatedClients = clients.map(c => {
      if (c.id === selectedClient.id) {
        return {
          ...c,
          equipments: c.equipments.map(e => {
            if (e.id === selectedEquipment.id) {

              let updatedVisits = [...e.visits];
              let updatedContract = { ...e.contract! };

              if (visitData.id) {
                // Update existing visit
                const oldVisit = e.visits.find(v => v.id === visitData.id);
                updatedVisits = e.visits.map(v => v.id === visitData.id ? { ...v, ...visitData } : v);

                // Note: Complex logic to revert contract usage and re-apply would go here in a real app
                // For this mockup, we assume editing a visit doesn't change the count logic unless we added removal logic.
              } else {
                // New Visit
                const newVisit: Visit = {
                    id: Math.random().toString(36).substr(2, 9),
                    equipmentId: selectedEquipment.id,
                    ...visitData
