            // Determine Payment
            // If PAGO has a date (e.g. 06/11/2025), it is paid on that date.
            // If PAGO has "Sim", it is paid.
            const pagoVal = String(row['PAGO'] || '').trim();
            let isPaid = false;
            let paymentDate = '';

            if (pagoVal) {
                const asDate = parseDate(pagoVal);
                if (asDate) {
                    isPaid = true;
                    paymentDate = asDate;
