          <p className="text-slate-500 capitalize">{monthName} {currentYear}</p>
        </div>
        <div className="flex gap-2">
          <div className="px-3 py-1 bg-blue-50 text-blue-700 text-xs font-bold rounded-full border border-blue-100 uppercase">
            {currentMonthVisits.length} Intervenções
          </div>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
        {currentMonthVisits.length === 0 ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400 p-12">
            <CalendarIcon className="w-16 h-16 mb-4 opacity-10" />
            <p className="text-lg font-medium">Sem visitas registadas para este mês.</p>
            <p className="text-sm">Agende novas intervenções através da ficha do equipamento.</p>
          </div>
        ) : (
          <div className="overflow-y-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-200 text-xs font-bold text-slate-500 uppercase tracking-wider">
                <tr>
                  <th className="px-6 py-4">Data</th>
                  <th className="px-6 py-4">Tipo / Técnico</th>
                  <th className="px-6 py-4">Cliente / Equipamento</th>
                  <th className="px-6 py-4">Observações</th>
                  <th className="px-6 py-4 text-right">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {currentMonthVisits.map((visit) => (
                  <tr key={visit.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
