                        <span className="text-[10px] text-slate-400 font-mono">ID: {visit.id}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1">
                        <span className={`text-xs px-2 py-0.5 rounded-full font-bold w-fit ${
                          visit.type === 'Reconstrução' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'
                        }`}>
                          {visit.type}
