                                        <FileText className="w-3 h-3" />
                                        {file.name}
                                        {file.url && <Download className="w-3 h-3 ml-1 opacity-50" />}
                                    </a>
                                ))}
                            </div>
                        )}
                      </div>
                    ))
                  )}
                </div>
              </div>

            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl bg-slate-50">
              <Scale className="w-12 h-12 mb-3 opacity-50" />
              <p>Selecione um equipamento para ver detalhes</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  // --- Main Layout ---
  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">

      {/* Sidebar Navigation */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col shadow-xl z-20">
        <div className="p-6 border-b border-slate-800">
          <div className="flex items-center gap-2 mb-2">
             <ShieldCheck className="w-5 h-5 text-blue-400" />
             <span className="text-[10px] font-bold uppercase tracking-widest text-blue-400/80">Administrador</span>
          </div>
          <h1 className="text-xl font-bold tracking-tight text-white">Marques Gestão</h1>
          <p className="text-xs text-slate-400 mt-1">Gestão de Contratos</p>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <NavItem 
            icon={<LayoutDashboard />} 
            label="Dashboard" 
            active={view === 'DASHBOARD'} 
            onClick={() => setView('DASHBOARD')} 
          />
          <NavItem 
            icon={<Users />} 
            label="Clientes & Equipamentos" 
            active={view === 'CLIENTS'} 
            onClick={() => setView('CLIENTS')} 
          />
          <NavItem 
            icon={<CalendarCheck />} 
            label="Agenda Mensal" 
            active={view === 'CALENDAR'} 
            onClick={() => setView('CALENDAR')} 
          />
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 rounded-lg bg-slate-800/50 text-sm">
            <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center font-bold">AD</div>
            <div>
              <p className="font-medium">Admin Marques</p>
              <p className="text-xs text-slate-400">Controlo Total</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 shadow-sm z-10">
          <h2 className="text-lg font-semibold text-slate-700">
            {view === 'DASHBOARD' && 'Visão Geral do Sistema'}
            {view === 'CLIENTS' && 'Gestão de Clientes'}
            {view === 'CALENDAR' && 'Agenda do Mês Atual'}
          </h2>
          <div className="flex items-center gap-4">
             <button 
                onClick={() => setIsImportModalOpen(true)}
                className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-700 hover:bg-emerald-100 rounded-md text-sm font-medium transition-colors border border-emerald-100"
             >
                <Upload className="w-4 h-4" />
                Importar Dados
             </button>
            <button className="p-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors">
              <Settings className="w-5 h-5" />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-hidden p-6 relative">
          {view === 'DASHBOARD' && <Dashboard clients={clients} />}

          {view === 'CLIENTS' && (
            <div className="flex h-full gap-6">
              {!selectedClient ? (
                <div className="w-full h-full overflow-hidden">
                  <ClientList 
                    clients={clients} 
                    onSelectClient={(c) => {
                      setSelectedClient(c);
                      setSelectedEquipment(null);
                    }}
                    onAddClient={() => {
                        setEditingClient(undefined);
                        setIsAddClientModalOpen(true);
                    }}
                    onDeleteClient={handleDeleteClient}
                  />
                </div>
              ) : (
                <div className="w-full h-full flex flex-col">
                  <button 
                    onClick={() => setSelectedClient(null)}
                    className="mb-4 text-sm text-slate-500 hover:text-blue-600 flex items-center gap-1 w-fit transition-colors"
                  >
                    ← Voltar à lista de clientes
                  </button>
                  <div className="flex-1 overflow-hidden">
                    {renderClientDetail()}
                  </div>
                </div>
              )}
            </div>
          )}

          {view === 'CALENDAR' && (
             <AgendaView clients={clients} />
          )}
        </div>
      </main>

      {/* Modals & Overlays */}
      {isImportModalOpen && (
        <ImportModal 
            onClose={() => setIsImportModalOpen(false)}
            onImport={handleImportData}
        />
      )}

      {isVisitModalOpen && selectedEquipment && (
        <VisitModal 
          initialData={editingVisit}
          equipment={selectedEquipment} 
          onClose={() => setIsVisitModalOpen(false)} 
          onSave={handleSaveVisit}
          onDelete={editingVisit ? handleDeleteVisit : undefined}
        />
      )}

      {isAddClientModalOpen && (
        <AddClientModal 
          initialData={editingClient}
          onClose={() => setIsAddClientModalOpen(false)}
          onSave={handleSaveClient}
        />
      )}

      {isAddEquipmentModalOpen && (
        <AddEquipmentModal 
          initialData={editingEquipment}
          onClose={() => setIsAddEquipmentModalOpen(false)}
          onSave={handleSaveEquipment}
        />
      )}

      {isPaymentModalOpen && selectedEquipment?.contract && (
        <PaymentModal 
          contract={selectedEquipment.contract}
          onClose={() => setIsPaymentModalOpen(false)}
          onSave={handleRegisterPayment}
        />
      )}

    </div>
  );
};

