import React, { useState } from 'react';
import { X, Upload, FileSpreadsheet, AlertCircle, Check } from 'lucide-react';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';
import { Client, Equipment, EquipmentType, VisitType } from '../types';

interface ImportModalProps {
  onClose: () => void;
  onImport: (clients: Client[]) => void;
}

const ImportModal: React.FC<ImportModalProps> = ({ onClose, onImport }) => {
  const [file, setFile] = useState<File | null>(null);
  const [error, setError] = useState<string>('');
  const [stats, setStats] = useState<{ clients: number, equipments: number } | null>(null);
  const [parsedData, setParsedData] = useState<Client[] | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError('');
      setStats(null);
      setParsedData(null);
    }
  };

  const parseDate = (dateStr: any): string => {
    if (!dateStr) return '';
    const str = String(dateStr).trim();

    // Handle excel/csv formats like DD/MM/YYYY or DD-MM-YYYY
    try {
        const parts = str.split(/[-/]/);
        if (parts.length === 3) {
            // Assume DD/MM/YYYY if first part is > 12 or if year is last
            if (parts[2].length === 4) {
                 return `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
            }
            // If format is YYYY-MM-DD (standard), return as is
            if (parts[0].length === 4) {
                 return str;
            }
        }
        // Try native Date parsing for other formats
        const d = new Date(str);
        if (!isNaN(d.getTime())) {
            return d.toISOString().split('T')[0];
        }
        return ''; 
    } catch {
        return '';
    }
  };

  const mapEquipmentType = (typeStr: string): EquipmentType => {
      if (!typeStr) return EquipmentType.Other;
      const lower = String(typeStr).toLowerCase();
      if (lower.includes('pcm') || lower.includes('ponte') || lower.includes('bascula')) return EquipmentType.PCM;
      if (lower.includes('pvs') || lower.includes('silo')) return EquipmentType.PVS;
      if (lower.includes('pvm') || lower.includes('movel')) return EquipmentType.PVM;
      return EquipmentType.Other;
  };

  const normalizeHeaders = (row: any): any => {
      const newRow: any = {};
      Object.keys(row).forEach(key => {
          let cleanKey = key.toString();
          // Replace newlines (\n, \r) and multiple spaces with a single space
          cleanKey = cleanKey.replace(/[\r\n]+/g, ' ').replace(/\s+/g, ' ').trim();
          // Remove surrounding quotes if they exist (common in CSV/Excel copy-paste)
          cleanKey = cleanKey.replace(/^"|"$/g, '');
          newRow[cleanKey] = row[key];
      });
      return newRow;
  };

  const processData = (rawData: any[]) => {
      try {
        const rows = rawData.map(normalizeHeaders);
        const clientsMap = new Map<string, Client>();

        rows.forEach((row, index) => {
            const clientName = row['CLIENTE'];
            if (!clientName) return; 

            // Extract Location & Identification Data
            const deliveryAddress = row['MORADA DE ENTREGA'] || '';
            const locality = row['LOCALIDADE'] || '';
            const municipality = row['CONCELHO'] || '';
            const district = row['DISTRITO'] || '';
            const executionSite = row['Local de Execução consolidado'] || '';

            // Technical Specs
            const serviceType = row['Tipo de Serviço'] || '';
            const serviceDesc = row['Descrição do Serviço'] || '';
            // Combine service type and description
            const fullDescription = [serviceType, serviceDesc].filter(Boolean).join(' - ');

            const equipmentType = row['TIPO EQUIPAMENTO'] || 'Equipamento';
            const capacity = row['CAPACIDADE CE'] || row['CAPACIDADE'] || '';
            const eqSerial = row['NÚMERO DE SÉRIE EQUIPAMENTO'] || 'N/A';
            const loadCells = row['CÉLULA DE CARGA'] || '';
            const viewer = row['VISOR'] || '';
            const viewerSerial = row['NÚMERO DE SÉRIE VISOR'] || '';

            // Contract Data
            const startDate = parseDate(row['DATA INICIO CONTRATO']);
            const endDate = parseDate(row['DATA FIM CONTRATO']);
            const visitsLight = parseInt(row['VISITA LIGEIRO']) || 0;
            const visitsTruck = parseInt(row['VISITA PESADO']) || 0;

            const estado = String(row['ESTADO'] || '').toLowerCase();
            // Basic heuristic: if status contains 'pago' or 'liquidado', mark as paid. 
            // Otherwise default to false (pending payment).
            const isPaid = estado.includes('pago') || estado.includes('liquidado');

            // --- Client Creation ---
            let client = clientsMap.get(clientName);
            if (!client) {
                client = {
                    id: `import-c-${Date.now()}-${index}`,
                    name: clientName,
                    address: deliveryAddress || 'Morada desconhecida', // Use delivery address as main if new
                    locality: locality,
                    district: district,
                    contactPerson: 'Não especificado', 
                    email: '', 
                    phone: '', 
                    equipments: []
                };
                clientsMap.set(clientName, client);
            }

            // --- Equipment Creation ---
            const equipment: Equipment = {
                id: `import-e-${Date.now()}-${index}`,
                clientId: client.id,

                // Mapped Fields
                deliveryAddress,
                locality,
                municipality,
                district,
                executionSite,
                description: fullDescription,

                // Primary display location (fallback chain)
                location: executionSite || deliveryAddress || locality || 'Local desconhecido',

                productName: equipmentType,
                weightCapacity: capacity,
                equipmentSerial: eqSerial,
                loadCells: loadCells,
                viewerModel: viewer,
                viewerSerial: viewerSerial,

                installDate: startDate || new Date().toISOString().split('T')[0],
                type: mapEquipmentType(equipmentType),
                visits: [],
                contract: {
                    id: `import-ctr-${Date.now()}-${index}`,
                    equipmentId: `import-e-${Date.now()}-${index}`,
                    startDate: startDate || new Date().toISOString().split('T')[0],
                    endDate: endDate || new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0],
                    invoiceNumber: '', // Not provided in headers
                    isPaid: isPaid,
                    totalLightVisits: visitsLight,
                    usedLightVisits: 0,
                    totalTruckVisits: visitsTruck,
                    usedTruckVisits: 0,
                    renewed: false
                }
            };

            client.equipments.push(equipment);
        });

        const clientsArray = Array.from(clientsMap.values());
        setParsedData(clientsArray);
        setStats({
            clients: clientsArray.length,
            equipments: clientsArray.reduce((acc, c) => acc + c.equipments.length, 0)
        });
      } catch (err) {
          console.error("Processing Error", err);
          setError("Erro ao processar os dados do ficheiro.");
      }
  };

  const handleParse = () => {
    if (!file) return;

    const fileType = file.name.split('.').pop()?.toLowerCase();

    if (fileType === 'csv') {
        Papa.parse(file, {
            header: true,
            skipEmptyLines: true,
            transformHeader: (h) => h.trim().replace(/"/g, ''),
            complete: (results) => {
                if (results.errors.length > 0) {
                    console.warn("CSV Errors:", results.errors);
                }
                processData(results.data as any[]);
            },
            error: (err) => {
                setError(`Erro CSV: ${err.message}`);
            }
        });
    } else if (fileType === 'xlsx' || fileType === 'xls') {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const data = e.target?.result;
                const workbook = XLSX.read(data, { type: 'array' });
                const firstSheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[firstSheetName];
                const jsonData = XLSX.utils.sheet_to_json(worksheet, { defval: "", raw: false });
                processData(jsonData);
            } catch (err) {
