import React, { useState } from 'react';
import { X, Upload, FileSpreadsheet, AlertCircle, Check } from 'lucide-react';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';
import { Client, Equipment, EquipmentType } from '../types';

interface ImportModalProps {
  onClose: () => void;
  onImport: (clients: Client[]) => void;
}

const ImportModal: React.FC<ImportModalProps> = ({ onClose, onImport }) => {
  const [file, setFile] = useState<File | null>(null);
  const [error, setError] = useState<string>('');
  const [stats, setStats] = useState<{ clients: number, equipments: number } | null>(null);
  const [parsedData, setParsedData] = useState<Client[] | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError('');
      setStats(null);
      setParsedData(null);
    }
  };

  // Helper to robustly parse dates from Excel/CSV
  const parseDate = (dateStr: any): string => {
    if (!dateStr) return '';
    const str = String(dateStr).trim();

    // Try standard YYYY-MM-DD
    if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;

    try {
        // Handle DD/MM/YYYY or DD-MM-YYYY
        const parts = str.split(/[-/]/);
        if (parts.length === 3) {
            const part0 = parseInt(parts[0]);
            const part1 = parseInt(parts[1]);
            const part2 = parseInt(parts[2]);

            // Assume Day/Month/Year if year is last (and > 1000)
            if (part2 > 1000) {
                 return `${part2}-${String(part1).padStart(2, '0')}-${String(part0).padStart(2, '0')}`;
            }
            // Assume Year/Month/Day if year is first
            if (part0 > 1000) {
                 return `${part0}-${String(part1).padStart(2, '0')}-${String(part2).padStart(2, '0')}`;
            }
        }

        // Fallback to JS Date parser
        const d = new Date(str);
        if (!isNaN(d.getTime())) {
            return d.toISOString().split('T')[0];
        }
        return ''; 
    } catch {
        return '';
    }
  };

  const mapEquipmentType = (typeStr: string): EquipmentType => {
      if (!typeStr) return EquipmentType.Other;
      const lower = String(typeStr).toLowerCase();
      if (lower.includes('pcm') || lower.includes('ponte') || lower.includes('bascula')) return EquipmentType.PCM;
      if (lower.includes('pvs') || lower.includes('silo')) return EquipmentType.PVS;
      if (lower.includes('pvm') || lower.includes('movel')) return EquipmentType.PVM;
      return EquipmentType.Other;
  };

  const processData = (rawData: any[][]) => {
      try {
        if (!rawData || rawData.length === 0) {
            setError("O ficheiro parece estar vazio.");
            return;
        }

        // 1. Locate the Header Row
        // Scan first 20 rows to find one containing 'CLIENTE' (case insensitive)
        let headerIndex = -1;
        for (let i = 0; i < Math.min(rawData.length, 20); i++) {
            const rowString = rawData[i].join(' ').toUpperCase();
            if (rowString.includes('CLIENTE')) {
                headerIndex = i;
                break;
            }
        }

        if (headerIndex === -1) {
            setError("Não foi encontrada a coluna 'CLIENTE'. Verifique se o ficheiro tem os cabeçalhos corretos.");
            return;
        }

        // 2. Extract Headers and Normalize to UpperCase
        const headers = rawData[headerIndex].map(h => String(h).trim().toUpperCase());
        const dataRows = rawData.slice(headerIndex + 1);

        const clientsMap = new Map<string, Client>();

        dataRows.forEach((rowArray, index) => {
            // Map row array to object using headers
            const row: Record<string, any> = {};
            headers.forEach((header, idx) => {
                if (header) {
                    row[header] = rowArray[idx];
                }
            });

            const clientName = row['CLIENTE'];
            if (!clientName) return; 

            // Extract Location
            const deliveryAddress = row['MORADA DE ENTREGA'] || row['MORADA'] || '';
            const locality = row['LOCALIDADE'] || '';
            const municipality = row['CONCELHO'] || '';
            const district = row['DISTRITO'] || '';
            const executionSite = row['LOCAL DE EXECUÇÃO CONSOLIDADO'] || row['LOCAL DE EXECUÇÃO'] || '';

            // Extract Technical Specs
            const serviceType = row['TIPO DE SERVIÇO'] || '';
            const serviceDesc = row['DESCRIÇÃO DO SERVIÇO'] || '';
            const fullDescription = [serviceType, serviceDesc].filter(Boolean).join(' - ');

            const equipmentType = row['TIPO EQUIPAMENTO'] || 'Equipamento';
            const capacity = row['CAPACIDADE CE'] || row['CAPACIDADE'] || '';
            const eqSerial = row['NÚMERO DE SÉRIE EQUIPAMENTO'] || row['Nº SÉRIE'] || 'N/A';
            const loadCells = row['CÉLULA DE CARGA'] || '';
            const viewer = row['VISOR'] || '';
            const viewerSerial = row['NÚMERO DE SÉRIE VISOR'] || '';

            // Extract Contract Data
            const startDate = parseDate(row['DATA INICIO CONTRATO']);
            const endDate = parseDate(row['DATA FIM CONTRATO']);
            const visitsLight = parseInt(row['VISITA LIGEIRO']) || 0;
            const visitsTruck = parseInt(row['VISITA PESADO']) || 0;

            const estado = String(row['ESTADO'] || '').toLowerCase();
            const isPaid = estado.includes('pago') || estado.includes('liquidado');

            // --- Client Creation or Retrieval ---
            let client = clientsMap.get(clientName);
            if (!client) {
                client = {
                    id: `import-c-${Date.now()}-${index}`,
                    name: clientName,
                    address: deliveryAddress || 'Morada desconhecida',
                    locality: locality,
                    district: district,
                    contactPerson: 'Não especificado', 
                    email: '', 
                    phone: '', 
                    equipments: []
                };
                clientsMap.set(clientName, client);
            }

            // --- Equipment Creation ---
            const equipment: Equipment = {
                id: `import-e-${Date.now()}-${index}`,
                clientId: client.id,

                // Location Details
                deliveryAddress,
                locality,
                municipality,
                district,
                executionSite,
                description: fullDescription,

                // Display Location Fallback
                location: executionSite || deliveryAddress || locality || 'Local desconhecido',

                // Specs
                productName: equipmentType,
                weightCapacity: capacity,
                equipmentSerial: eqSerial,
                loadCells: loadCells,
                viewerModel: viewer,
                viewerSerial: viewerSerial,

                installDate: startDate || new Date().toISOString().split('T')[0],
                type: mapEquipmentType(equipmentType),
                visits: [],
                contract: {
                    id: `import-ctr-${Date.now()}-${index}`,
                    equipmentId: `import-e-${Date.now()}-${index}`,
                    startDate: startDate || new Date().toISOString().split('T')[0],
                    endDate: endDate || new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0],
                    invoiceNumber: '',
                    isPaid: isPaid,
                    totalLightVisits: visitsLight,
                    usedLightVisits: 0,
                    totalTruckVisits: visitsTruck,
                    usedTruckVisits: 0,
                    renewed: false
                }
            };

            client.equipments.push(equipment);
        });

        const clientsArray = Array.from(clientsMap.values());

        if (clientsArray.length === 0) {
            setError("Não foi possível extrair dados válidos. Verifique as colunas.");
        } else {
            setParsedData(clientsArray);
            setStats({
                clients: clientsArray.length,
                equipments: clientsArray.reduce((acc, c) => acc + c.equipments.length, 0)
            });
        }

      } catch (err) {
          console.error("Processing Error", err);
          setError("Erro ao processar os dados do ficheiro.");
      }
  };

  const handleParse = () => {
    if (!file) return;

    const fileType = file.name.split('.').pop()?.toLowerCase();

    if (fileType === 'csv') {
        Papa.parse(file, {
            header: false, // Ensure we get array of arrays
            skipEmptyLines: true,
            complete: (results) => {
                if (results.errors.length > 0) {
                    console.warn("CSV Errors:", results.errors);
                }
                processData(results.data as any[][]);
            },
            error: (err) => {
                setError(`Erro CSV: ${err.message}`);
            }
        });
    } else if (fileType === 'xlsx' || fileType === 'xls') {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const data = e.target?.result;
                const workbook = XLSX.read(data, { type: 'array' });
                const firstSheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[firstSheetName];
                // Use header: 1 to get raw array of arrays
                const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: "", raw: false });
                processData(jsonData as any[][]);
            } catch (err) {
                console.error("Excel Parse Error", err);
                setError("Erro ao ler ficheiro Excel.");
            }
        };
        reader.onerror = () => setError("Erro ao ler o ficheiro.");
        reader.readAsArrayBuffer(file);
    } else {
        setError("Formato de ficheiro não suportado.");
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="bg-emerald-600 p-4 flex justify-between items-center text-white">
          <h3 className="font-semibold text-lg flex items-center gap-2">
            <FileSpreadsheet className="w-5 h-5" />
            Importar Dados (Excel/CSV)
          </h3>
          <button onClick={onClose} className="hover:bg-emerald-700 p-1 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-4">
            {!stats ? (
                <>
                    <div className="border-2 border-dashed border-slate-300 rounded-xl p-8 text-center bg-slate-50 hover:bg-slate-100 transition-colors">
                        <input 
                            type="file" 
                            accept=".csv, .xlsx, .xls" 
                            onChange={handleFileChange} 
                            className="hidden" 
                            id="csvInput"
                        />
                        <label htmlFor="csvInput" className="cursor-pointer flex flex-col items-center">
                            <Upload className="w-10 h-10 text-emerald-500 mb-2" />
                            <span className="text-sm font-medium text-slate-700">Clique para selecionar ficheiro</span>
                            <span className="text-xs text-slate-400 mt-1">Formatos suportados: .xlsx, .xls, .csv</span>
                        </label>
                    </div>
                    {file && (
                        <div className="flex items-center gap-2 text-sm text-slate-700 bg-slate-100 p-2 rounded">
                            <FileSpreadsheet className="w-4 h-4" />
                            {file.name}
                        </div>
                    )}
                    {error && (
                        <div className="flex items-center gap-2 text-sm text-red-600 bg-red-50 p-2 rounded">
                            <AlertCircle className="w-4 h-4" />
                            {error}
                        </div>
                    )}
                    <button
                        onClick={handleParse}
                        disabled={!file}
                        className="w-full py-2 bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-medium transition-colors"
                    >
                        Analisar Ficheiro
                    </button>
                </>
            ) : (
                <div className="space-y-4">
                    <div className="bg-emerald-50 p-4 rounded-lg border border-emerald-100">
                        <h4 className="font-semibold text-emerald-900 mb-2 flex items-center gap-2">
                            <Check className="w-4 h-4" /> Análise Concluída
                        </h4>
                        <ul className="space-y-1 text-sm text-emerald-800">
                            <li>• {stats.clients} Clientes encontrados</li>
                            <li>• {stats.equipments} Equipamentos encontrados</li>
                        </ul>
                    </div>
                    <div className="flex gap-3">
                        <button
                            onClick={() => { setStats(null); setFile(null); }}
                            className="flex-1 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                        >
                            Voltar
                        </button>
                        <button
                            onClick={() => parsedData && onImport(parsedData)}
                            className="flex-1 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700"
                        >
                            Confirmar Importação
                        </button>
                    </div>
                </div>
            )}

            <div className="mt-4 pt-4 border-t border-slate-100 text-[10px] text-slate-400">
                <p>O sistema procurará automaticamente pela coluna <strong>CLIENTE</strong>. Certifique-se que o seu Excel contém esta coluna, juntamente com MORADA DE ENTREGA, TIPO EQUIPAMENTO, etc.</p>
            </div>
        </div>
      </div>
    </div>
  );
};

export default ImportModal;

