  // Helper to robustly parse dates from Excel/CSV
  const parseDate = (dateStr: any): string => {
    if (!dateStr) return '';
    const str = String(dateStr).trim();

    // Try standard YYYY-MM-DD
    if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;

    try {
        // Handle Excel serial dates (numbers like 45321)
        if (!isNaN(Number(str)) && Number(str) > 20000) {
            // Approx for Excel date serials (days since 1900-01-01)
            const excelDate = new Date((Number(str) - (25567 + 2)) * 86400 * 1000);
            return excelDate.toISOString().split('T')[0];
        }

        // Handle DD/MM/YYYY or DD-MM-YYYY
        const parts = str.split(/[-/]/);
        if (parts.length === 3) {
            const part0 = parseInt(parts[0]);
            const part1 = parseInt(parts[1]);
            const part2 = parseInt(parts[2]);

            // Assume Day/Month/Year if year is last (and > 1000)
            if (part2 > 1000) {
                 return `${part2}-${String(part1).padStart(2, '0')}-${String(part0).padStart(2, '0')}`;
            }
            // Assume Year/Month/Day if year is first
            if (part0 > 1000) {
                 return `${part0}-${String(part1).padStart(2, '0')}-${String(part2).padStart(2, '0')}`;
            }
        }

        // Fallback to JS Date parser
        const d = new Date(str);
        if (!isNaN(d.getTime())) {
            return d.toISOString().split('T')[0];
        }
        return ''; 
    } catch {
        return '';
    }
  };

  const mapEquipmentType = (typeStr: string): EquipmentType => {
      if (!typeStr) return EquipmentType.Other;
      const lower = String(typeStr).toLowerCase();
      if (lower.includes('pcm') || lower.includes('ponte') || lower.includes('bascula')) return EquipmentType.PCM;
      if (lower.includes('pvs') || lower.includes('silo')) return EquipmentType.PVS;
      if (lower.includes('pvm') || lower.includes('movel')) return EquipmentType.PVM;
      return EquipmentType.Other;
  };

  const processData = (rawData: any[][]) => {
