        const dataRows = rawData.slice(headerIndex + 1);

        const clientsMap = new Map<string, Client>();

        dataRows.forEach((rowArray, index) => {
            // Map row array to object using headers
            const row: Record<string, any> = {};
            headers.forEach((header, idx) => {
                if (header) {
                    row[header] = rowArray[idx];
                }
            });

            const clientName = row['CLIENTE'];
            if (!clientName) return; 

            // Extract Location Information
            const deliveryAddress = row['MORADA DE ENTREGA'] || '';
            const locality = row['LOCALIDADE'] || '';
            const municipality = row['CONCELHO'] || '';
            const district = row['DISTRITO'] || '';
            const executionSite = row['LOCAL DE EXECUÇÃO CONSOLIDADO'] || '';

            // Extract Technical Specs
            const serviceType = row['TIPO DE SERVIÇO'] || '';
            const serviceDesc = row['DESCRIÇÃO DO SERVIÇO'] || '';
            const fullDescription = [serviceType, serviceDesc].filter(Boolean).join(' - ');

            const equipmentType = row['TIPO EQUIPAMENTO'] || 'Equipamento';
            const capacity = row['CAPACIDADE CE'] || '';
            const eqSerial = row['NÚMERO DE SÉRIE EQUIPAMENTO'] || 'N/A';
            const loadCells = row['CÉLULA DE CARGA'] || '';
            const viewer = row['VISOR'] || '';
            const viewerSerial = row['NÚMERO DE SÉRIE VISOR'] || '';

            // Extract Contract Data
            const startDate = parseDate(row['DATA INICIO']);
            const endDate = parseDate(row['DATA FIM']);
            const visitsLight = parseInt(row['VISITA LIGEIRO']) || 0;
            const visitsTruck = parseInt(row['VISITA PESADO']) || 0;

            const estado = String(row['ESTADO'] || '').toLowerCase();
            const isPaid = estado.includes('pago') || estado.includes('liquidado');

            // --- Client Creation or Retrieval ---
            let client = clientsMap.get(clientName);
            if (!client) {
                client = {
                    id: `import-c-${Date.now()}-${index}`,
                    name: clientName,
                    address: deliveryAddress || 'Morada desconhecida',
                    locality: locality,
                    district: district,
                    contactPerson: 'Não especificado', 
                    email: '', 
                    phone: '', 
                    equipments: []
                };
                clientsMap.set(clientName, client);
            }

            // --- Equipment Creation ---
            const equipment: Equipment = {
                id: `import-e-${Date.now()}-${index}`,
                clientId: client.id,

                // Location Details
                deliveryAddress,
                locality,
                municipality,
                district,
                executionSite,
                description: fullDescription,

                // Display Location Fallback
                location: executionSite || deliveryAddress || locality || 'Local desconhecido',

                // Specs
                productName: equipmentType,
                weightCapacity: capacity,
                equipmentSerial: eqSerial,
                loadCells: loadCells,
                viewerModel: viewer,
                viewerSerial: viewerSerial,

                installDate: startDate || new Date().toISOString().split('T')[0],
                type: mapEquipmentType(equipmentType),
                visits: [],
                contract: {
                    id: `import-ctr-${Date.now()}-${index}`,
                    equipmentId: `import-e-${Date.now()}-${index}`,
                    startDate: startDate || new Date().toISOString().split('T')[0],
                    endDate: endDate || new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0],
                    invoiceNumber: '',
                    isPaid: isPaid,
                    totalLightVisits: visitsLight,
                    usedLightVisits: 0,
                    totalTruckVisits: visitsTruck,
                    usedTruckVisits: 0,
