                    id: `imp-c-${index}`,
                    name: clientName,
                    address: morada || 'Morada desconhecida',
                    locality: localidade,
                    district: distrito,
                    contactPerson: 'Gestão de Contratos',
                    email: '',
                    phone: '',
                    equipments: []
                };
                clientsMap.set(clientName, client);
            }

            // Equipment Mgmt
